let deg = 0

interface Icolor {
  'R': number;
  'G': number;
  'B': number;
}

let color1 = {'R':0xff,'G':0,'B':0}
let color2 = {'R':0,'G':0xff,'B':0}

const ColroGener = (color: Icolor) => {
  let c = '#'
  c += color.R < 16 ? '0' + color.R.toString(16) : color.R.toString(16)
  c += color.G < 16 ? '0' + color.G.toString(16) : color.G.toString(16)
  c += color.B < 16 ? '0' + color.B.toString(16) : color.B.toString(16)
  return c
}

const ColorTrans=((color: Icolor) => {
  const colorstr = ColroGener(color)
  if      (color.R==0xff && color.G==0x00 && color.B!=0xff)  //#ff0000 - #ff00ff
    color.B += 1
  else if (color.R!=0x00 && color.G==0x00 && color.B==0xff)  //#ff00ff - #0000ff
    color.R -= 1
  else if (color.R==0x00 && color.G!=0xff && color.B==0xff)  //#0000ff - #00ffff
    color.G += 1
  else if (color.R==0x00 && color.G==0xff && color.B!=0x00)  //#00ffff - #00ff00
    color.B -= 1
  else if (color.R!=0xff && color.G==0xff && color.B==0x00)  //#00ff00 - #ffff00
    color.R += 1
  else if (color.R==0xff && color.G!=0x00 && color.B==0x00)  //#ffff00 - #ff0000
    color.G -= 1
  return color
})

const RBG = () => {
  color1 = ColorTrans(color1)
  color2 = ColorTrans(color2)
  deg = (deg+0.1) % 360
  document.body.style.background = `linear-gradient(${deg}deg, ${ColroGener(color1)}22 0%, ${ColroGener(color2)}22 100%)`
  setTimeout(RBG,10)
}
export {RBG}