
import * as UCNowTime from './components/UCNowTime'
import * as UCRandomBG from './components/UCRandomBG'
import {
    onMounted
} from 'vue';

export default {
    name: 'App',
    setup() {
        const enter = (url: string) => {
            window.open(url)
        }
        onMounted(() => {
            UCNowTime.getNow()
            UCRandomBG.RBG()
        })
        const nowTime = UCNowTime.nowTime
        const getNow = UCNowTime.getNow

        return {
            enter,
            nowTime,
            getNow,
        }
    }

};
